"""Stage 2: Normalize field names and handle missing values.

Converts field names to lowercase snake_case and fills in defaults
for missing/empty values.
"""

# TODO: handle edge cases for unicode field names

DEFAULTS = {
    'quantity': 0.0,
    'unit_price': 0.0,
    'category': 'unknown',
}


def normalize(records):
    """Normalize field names and fill missing values."""
    normalized = []
    for record in records:
        row = {}
        for key, value in record.items():
            # Normalize key: lowercase, replace spaces with underscores
            norm_key = key.lower().replace(' ', '_')
            row[norm_key] = value

        # Fill defaults for missing fields
        for field, default in DEFAULTS.items():
            if field not in row or row[field] == '':
                row[field] = default

        normalized.append(row)

    return normalized

seed_files.pipeline/export.py:
"""Stage 5: Export aggregated data to JSON-compatible format.

Formats the output and filters out empty/zero groups.
"""


def export(groups):
    """Format aggregated groups for JSON export.

    Returns a list of formatted dicts.  Fields with no meaningful value
    are omitted to keep the output compact.
    """
    output = []
    for group in groups:
        entry = {'category': group['category']}

        if group.get('count'):
            entry['count'] = group['count']

        if group.get('total'):
            entry['total'] = group['total']

        if group.get('avg_price'):
            entry['avg_price'] = group['avg_price']

        output.append(entry)

    return output

